#include <bits/stdc++.h>
using namespace std;

const short P=11380;

short la,lb,lc,d,f[11][11][11][11][11][11];

void add(short &x,short y){
    x=(x+y)%P;
}

short solve(short d){
    if(d<0)
        return 0;
    memset(f,0,sizeof(f));
    f[0][0][0][0][0][0]=1;
    for(short i=0;i<=la;i++)
        for(short j=0;j<=lb;j++)
            for(short k=0;k<=lc;k++)
                for(short a=i;a>=0;a--)
                    for(short b=j;b>=0;b--)
                        for(short c=k;c>=0;c--){
                            if(a+b+c>d)
                                continue;
                            short num=f[i][j][k][a][b][c];
                            if(a+b+c<d){
                                if(k<lc)
                                    add(f[i][j][k+1][a][b][c+1],num);
                                if(!c && j<lb)
                                    add(f[i][j+1][k][a][b+1][c],num);
                                if(!(b+c) && i<la)
                                    add(f[i+1][j][k][a+1][b][c],num);
                            }
                            if(c)
                                add(f[i][j][k][a][b][c-1],num);
                            if(!c && b)
                                add(f[i][j][k][a][b-1][c],num);
                            if(!(b+c) && a)
                                add(f[i][j][k][a-1][b][c],num);
                        }
    return f[la][lb][lc][0][0][0];
}

int main(){
    cin>>la>>lb>>lc>>d;
    cout<<(solve(d)-solve(d-1)+P)%P;
    return 0;
}
